import React, { useState } from 'react';
import { createRoot } from 'react-dom/client';
import { Button } from '../design-system/Button/Button';
import { Input } from '../design-system/Input/Input';
import { Select } from '../design-system/Select/Select';
import { Modal } from '../design-system/Modal/Modal';
import { Card } from '../design-system/Card/Card';
import { Badge, Tabs } from '../design-system/Badge/Badge';
import { PatientHeader, VitalsPanel, MedicationList, AllergyBadge, ProblemList } from '../clinical/index';
import '../theme/variables.css';

function TestComponent() {
  const [count, setCount] = useState(0);
  const [modalOpen, setModalOpen] = useState(false);
  const [text, setText] = useState('');
  const [activeTab, setActiveTab] = useState('overview');

  return (
    <div style={{ maxWidth: 900, margin: '0 auto', padding: 'var(--spacing-6)' }}>
      <h1 style={{ marginBottom: 'var(--spacing-6)', fontSize: 'var(--font-size-3xl)' }}>
        Oscar UI Component Library
      </h1>

      <Tabs
        tabs={[
          { key: 'overview', label: 'Design System' },
          { key: 'clinical', label: 'Clinical Components' },
        ]}
        activeKey={activeTab}
        onChange={setActiveTab}
      />

      {activeTab === 'overview' && (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--spacing-6)', marginTop: 'var(--spacing-6)' }}>
          <Card title="Buttons">
            <div style={{ display: 'flex', gap: 'var(--spacing-3)', flexWrap: 'wrap', alignItems: 'center' }}>
              <Button>Primary</Button>
              <Button variant="secondary">Secondary</Button>
              <Button variant="danger">Danger</Button>
              <Button variant="ghost">Ghost</Button>
              <Button size="sm">Small</Button>
              <Button size="lg">Large</Button>
              <Button loading>Loading</Button>
              <Button disabled>Disabled</Button>
            </div>
          </Card>

          <Card title="Inputs">
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 'var(--spacing-4)' }}>
              <Input label="First Name" placeholder="Enter name" value={text} onChange={e => setText(e.target.value)} />
              <Input label="Email" type="email" placeholder="user@example.com" error={text.length > 0 && !text.includes('@') ? 'Invalid email' : undefined} />
              <Select label="Province" options={[{ value: 'BC', label: 'British Columbia' }, { value: 'ON', label: 'Ontario' }]} />
            </div>
          </Card>

          <Card title="Badges">
            <div style={{ display: 'flex', gap: 'var(--spacing-2)', flexWrap: 'wrap' }}>
              <Badge variant="success">Success</Badge>
              <Badge variant="warning">Warning</Badge>
              <Badge variant="error">Error</Badge>
              <Badge variant="info">Info</Badge>
              <Badge variant="neutral">Neutral</Badge>
            </div>
          </Card>

          <Card title="Modal">
            <Button onClick={() => setModalOpen(true)}>Open Modal</Button>
            <Modal
              open={modalOpen}
              onClose={() => setModalOpen(false)}
              title="Confirm Action"
              footer={
                <>
                  <Button variant="secondary" onClick={() => setModalOpen(false)}>Cancel</Button>
                  <Button onClick={() => { setCount(c => c + 1); setModalOpen(false); }}>Confirm (clicked {count}x)</Button>
                </>
              }
            >
              <p>This is a modal dialog with focus trap and Escape key support.</p>
            </Modal>
          </Card>
        </div>
      )}

      {activeTab === 'clinical' && (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--spacing-4)', marginTop: 'var(--spacing-4)' }}>
          <PatientHeader
            name="Sarah Johnson"
            dob="1990-06-03"
            age={36}
            hin="9876-543-21-BC"
            sex="F"
            providerName="Smith"
            allergies={['Sulfa', 'Penicillin']}
          />

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 'var(--spacing-4)' }}>
            <VitalsPanel vitals={[
              { label: 'BP', value: '120/80', unit: 'mmHg', trend: 'stable' },
              { label: 'HR', value: '72', unit: 'bpm', trend: 'stable' },
              { label: 'Temp', value: '37.0', unit: '°C', trend: 'stable' },
              { label: 'O2', value: '98', unit: '%', trend: 'stable' },
            ]} />

            <Card title="Allergies">
              <AllergyBadge allergies={[
                { name: 'Sulfa', severity: 'severe' },
                { name: 'Penicillin', severity: 'moderate' },
                { name: 'Latex', severity: 'mild' },
              ]} />
            </Card>
          </div>

          <MedicationList medications={[
            { name: 'Metformin', dose: '500mg', route: 'PO', frequency: 'BID', startDate: '2025-01-15' },
            { name: 'Ramipril', dose: '5mg', route: 'PO', frequency: 'Daily', startDate: '2025-03-01' },
          ]} />

          <ProblemList problems={[
            { code: 'E11.9', name: 'Type 2 Diabetes Mellitus', onsetDate: '2024-06-01', status: 'active' },
            { code: 'I10', name: 'Essential Hypertension', onsetDate: '2024-06-01', status: 'active' },
          ]} />
        </div>
      )}
    </div>
  );
}

// Mount to the DOM element Oscar provides
const rootElement = document.getElementById('oscar-ui-root');
if (rootElement) {
  createRoot(rootElement).render(<TestComponent />);
}
